import React from 'react';
import { NativeModules } from 'react-native';

const InAppPurchase = NativeModules.InAppPurchase;

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
      purchases: [],
    };
  }

  componentDidMount() {
    InAppPurchase.getProducts((products) => {
      this.setState({ products });
    });
  }

  purchaseProduct(productId) {
    InAppPurchase.purchaseProduct(productId, (purchase) => {
      this.setState({ purchases: [...this.state.purchases, purchase] });
    });
  }

  render() {
    return (
      <View>
        {this.state.products.map((product) => (
          <Button title={product.title} onPress={() => this.purchaseProduct(product.productId)} />
        ))}
      </View>
    );
  }
}

export default PaymentModule;